const input = $input.first().json;
let transcript = '';
if (typeof input === 'string') { transcript = input; }
else if (typeof input.transcript === 'string') { transcript = input.transcript; }
else if (typeof input.text === 'string') { transcript = input.text; }
else if (Array.isArray(input)) { transcript = input.map(i => i.text || i.transcript || '').join(' '); }
else if (Array.isArray(input.transcripts)) { transcript = input.transcripts.map(i => i.text || '').join(' '); }
else { const raw = JSON.stringify(input); const matches = [...raw.matchAll(/\"text\":\"(.*?)\"/g)]; transcript = matches.map(m => m[1]).join(' '); }
transcript = transcript.replace(/\[\d{2}:\d{2}(?::\d{2})?\]/g, ' ').replace(/\(\d{2}:\d{2}(?::\d{2})?\)/g, ' ').replace(/\s+/g, ' ').trim();
if (!transcript || transcript.length < 50) throw new Error('Transcript is empty or too short.');
return [{ json: { youtubeUrl: $('When Form Submitted').first().json['YouTube Video URL'], transcript, transcriptLength: transcript.length } }];

const ai = $input.first().json;
let text = ai.text || ai.content || ai.response || ai.message || JSON.stringify(ai);
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const start = text.indexOf('{');
const end = text.lastIndexOf('}');
if (start === -1 || end === -1) throw new Error('AI did not return valid JSON.');
const raw = text.slice(start, end + 1);
let parsed;
try { parsed = JSON.parse(raw); } catch (e) { throw new Error('Failed to parse AI JSON: ' + e.message); }
const required = ['title','summary','blog','linkedin','twitter_thread','newsletter','content_ideas','viral_hooks','cta_suggestions'];
for (const key of required) { if (!parsed[key]) parsed[key] = ''; }
const transcriptData = $('Process YouTube Transcript').first().json;
return [{ json: { timestamp: new Date().toISOString(), youtubeUrl: transcriptData.youtubeUrl, transcript: transcriptData.transcript, title: parsed.title, summary: parsed.summary, blog: parsed.blog, linkedin: parsed.linkedin, twitter_thread: parsed.twitter_thread, newsletter: parsed.newsletter, content_ideas: parsed.content_ideas, viral_hooks: parsed.viral_hooks, cta_suggestions: parsed.cta_suggestions, linkedin_status: 'Pending', created_date: new Date().toISOString().split('T')[0] } }];

const err = $input.first().json;
const msg = err.error?.message || err.message || JSON.stringify(err);
const node = err.error?.node?.name || 'Unknown Node';
return [{ json: { Timestamp: new Date().toISOString(), 'YouTube URL': (() => { try { return $('When Form Submitted').first().json['YouTube Video URL']; } catch (e) { return ''; } })(), 'Error Message': msg, 'Error Node': node } }];
